212	njs_inline njs_bool_t
213	njs_query_string_is_native_decoder(njs_function_t *decoder)
214	{
215	    njs_opaque_value_t     function;
216	    njs_function_native_t  native;
217	
218	    if (decoder == NULL) {
219	        return 1;
220	    }
221	
222	    njs_value_function_set(njs_value_arg(&function), decoder);
223	
224	    native = njs_value_native_function(njs_value_arg(&function));
225	
226	    return native == njs_query_string_unescape;
227	}
