230	njs_inline njs_int_t
231	njs_query_string_append(njs_vm_t *vm, njs_value_t *object, const u_char *key,
232	    size_t key_size, const u_char *val, size_t val_size,
233	    njs_function_t *decoder)
234	{
235	    njs_int_t           ret;
236	    njs_value_t         *push;
237	    njs_opaque_value_t  array, name, value, retval;
238	
239	    if (njs_query_string_is_native_decoder(decoder)) {
240	        ret = njs_query_string_decode(vm, njs_value_arg(&name), key, key_size);
241	        if (njs_slow_path(ret != NJS_OK)) {
242	            return ret;
243	        }
244	
245	        ret = njs_query_string_decode(vm, njs_value_arg(&value), val, val_size);
246	        if (njs_slow_path(ret != NJS_OK)) {
247	            return ret;
248	        }
249	
250	    } else {
251	
252	        ret = njs_vm_value_string_create(vm, njs_value_arg(&name), key,
253	                                         key_size);
254	        if (njs_slow_path(ret != NJS_OK)) {
255	            return ret;
256	        }
257	
258	        if (key_size > 0) {
259	            ret = njs_vm_invoke(vm, decoder, njs_value_arg(&name), 1,
260	                                njs_value_arg(&name));
261	            if (njs_slow_path(ret != NJS_OK)) {
262	                return ret;
263	            }
264	
265	            if (!njs_value_is_string(njs_value_arg(&name))) {
266	                ret = njs_value_to_string(vm, njs_value_arg(&name),
267	                                          njs_value_arg(&name));
268	                if (njs_slow_path(ret != NJS_OK)) {
269	                    return ret;
270	                }
271	            }
272	        }
273	
274	        ret = njs_vm_value_string_create(vm, njs_value_arg(&value), val,
275	                                         val_size);
276	        if (njs_slow_path(ret != NJS_OK)) {
277	            return ret;
278	        }
279	
280	        if (val_size > 0) {
281	            ret = njs_vm_invoke(vm, decoder, njs_value_arg(&value), 1,
282	                                njs_value_arg(&value));
283	            if (njs_slow_path(ret != NJS_OK)) {
284	                return ret;
285	            }
286	
287	            if (!njs_value_is_string(njs_value_arg(&value))) {
288	                ret = njs_value_to_string(vm, njs_value_arg(&value),
289	                                          njs_value_arg(&value));
290	                if (njs_slow_path(ret != NJS_OK)) {
291	                    return ret;
292	                }
293	            }
294	        }
295	    }
296	
297	    ret = njs_value_property_val(vm, object, njs_value_arg(&name),
298	                                 njs_value_arg(&retval));
299	
300	    if (ret == NJS_OK) {
301	        if (njs_value_is_array(njs_value_arg(&retval))) {
302	            push = njs_vm_array_push(vm, njs_value_arg(&retval));
303	            if (njs_slow_path(push == NULL)) {
304	                return NJS_ERROR;
305	            }
306	
307	            njs_value_assign(push, njs_value_arg(&value));
308	
309	            return NJS_OK;
310	        }
311	
312	        ret = njs_vm_array_alloc(vm, njs_value_arg(&array), 2);
313	        if (njs_slow_path(ret != NJS_OK)) {
314	            return ret;
315	        }
316	
317	        push = njs_vm_array_push(vm, njs_value_arg(&array));
318	        if (njs_slow_path(push == NULL)) {
319	            return NJS_ERROR;
320	        }
321	
322	        njs_value_assign(push, njs_value_arg(&retval));
323	
324	        push = njs_vm_array_push(vm, njs_value_arg(&array));
325	        if (njs_slow_path(push == NULL)) {
326	            return NJS_ERROR;
327	        }
328	
329	        njs_value_assign(push, njs_value_arg(&value));
330	
331	        njs_value_assign(&value, &array);
332	    }
333	
334	    return njs_value_property_val_set(vm, object, njs_value_arg(&name),
335	                                      njs_value_arg(&value));
336	}
