339	static u_char *
340	njs_query_string_match(u_char *p, u_char *end, const njs_str_t *v)
341	{
342	    size_t  length;
343	
344	    length = v->length;
345	
346	    if (njs_fast_path(length == 1)) {
347	        p = njs_strlchr(p, end, v->start[0]);
348	
349	        if (p == NULL) {
350	            p = end;
351	        }
352	
353	        return p;
354	    }
355	
356	    while (p <= (end - length)) {
357	        if (memcmp(p, v->start, length) == 0) {
358	            return p;
359	        }
360	
361	        p++;
362	    }
363	
364	    return end;
365	}
