368	static njs_int_t
369	njs_query_string_parse(njs_vm_t *vm, njs_value_t *args, njs_uint_t nargs,
370	    njs_index_t unused, njs_value_t *retval)
371	{
372	    int64_t             max_keys;
373	    njs_int_t           ret;
374	    njs_str_t           str, sep, eq;
375	    njs_value_t         *this, *string, *options, *arg, *val;
376	    njs_function_t      *decode;
377	    njs_opaque_value_t  value, val_sep, val_eq;
378	
379	    decode = NULL;
380	    max_keys = 1000;
381	
382	    this = njs_argument(args, 0);
383	    string = njs_arg(args, nargs, 1);
384	
385	    if (njs_value_is_string(string)) {
386	        njs_value_string_get(vm, string, &str);
387	
388	    } else {
389	        str = njs_str_value("");
390	    }
391	
392	    sep = njs_sep_default;
393	    eq = njs_eq_default;
394	
395	    arg = njs_arg(args, nargs, 2);
396	    if (!njs_value_is_null_or_undefined(arg)) {
397	        ret = njs_value_to_string(vm, njs_value_arg(&val_sep), arg);
398	        if (njs_slow_path(ret != NJS_OK)) {
399	            return ret;
400	        }
401	
402	        if (njs_value_string_length(vm, njs_value_arg(&val_sep)) != 0) {
403	            njs_value_string_get(vm, njs_value_arg(&val_sep), &sep);
404	        }
405	    }
406	
407	    arg = njs_arg(args, nargs, 3);
408	    if (!njs_value_is_null_or_undefined(arg)) {
409	        ret = njs_value_to_string(vm, njs_value_arg(&val_eq), arg);
410	        if (njs_slow_path(ret != NJS_OK)) {
411	            return ret;
412	        }
413	
414	        if (njs_value_string_length(vm, njs_value_arg(&val_eq)) != 0) {
415	            njs_value_string_get(vm, njs_value_arg(&val_eq), &eq);
416	        }
417	    }
418	
419	    options = njs_arg(args, nargs, 4);
420	
421	    if (njs_value_is_object(options)) {
422	        val = njs_vm_object_prop(vm, options, &njs_max_keys_str, &value);
423	
424	        if (val != NULL) {
425	            if (!njs_value_is_valid_number(val)) {
426	                njs_vm_type_error(vm, "is not a number");
427	                return NJS_ERROR;
428	            }
429	
430	            max_keys = njs_value_number(val);
431	
432	            if (max_keys == 0) {
433	                max_keys = INT64_MAX;
434	            }
435	        }
436	
437	        val = njs_vm_object_prop(vm, options, &njs_decode_uri_str, &value);
438	
439	        if (val != NULL) {
440	            if (njs_slow_path(!njs_value_is_function(val))) {
441	                njs_vm_type_error(vm, "option decodeURIComponent is not "
442	                                  "a function");
443	                return NJS_ERROR;
444	            }
445	
446	            decode = njs_value_function(val);
447	        }
448	    }
449	
450	    if (decode == NULL) {
451	        val = njs_vm_object_prop(vm, this, &njs_unescape_str, &value);
452	
453	        if (val == NULL || !njs_value_is_function(val)) {
454	            njs_vm_type_error(vm, "QueryString.unescape is not a function");
455	            return NJS_ERROR;
456	        }
457	
458	        decode = njs_value_function(val);
459	    }
460	
461	    return njs_query_string_parser(vm, str.start, str.start + str.length,
462	                                   &sep, &eq, decode, max_keys, retval);
463	}
