475	static njs_int_t
476	njs_query_string_parser(njs_vm_t *vm, u_char *query, u_char *end,
477	    const njs_str_t *sep, const njs_str_t *eq, njs_function_t *decode,
478	    njs_uint_t max_keys, njs_value_t *retval)
479	{
480	    size_t      size;
481	    u_char      *part, *key, *val;
482	    njs_int_t   ret;
483	    njs_uint_t  count;
484	
485	    ret = njs_vm_object_alloc(vm, retval, NULL);
486	    if (njs_slow_path(ret != NJS_OK)) {
487	        return NJS_ERROR;
488	    }
489	
490	    count = 0;
491	
492	    key = query;
493	
494	    while (key < end) {
495	        if (count++ == max_keys) {
496	            break;
497	        }
498	
499	        part = njs_query_string_match(key, end, sep);
500	
501	        if (part == key) {
502	            goto next;
503	        }
504	
505	        val = njs_query_string_match(key, part, eq);
506	
507	        size = val - key;
508	
509	        if (val != part) {
510	            val += eq->length;
511	        }
512	
513	        ret = njs_query_string_append(vm, retval, key, size, val, part - val,
514	                                      decode);
515	        if (njs_slow_path(ret != NJS_OK)) {
516	            return ret;
517	        }
518	
519	    next:
520	
521	        key = part + sep->length;
522	    }
523	
524	    return NJS_OK;
525	}
