528	njs_inline njs_int_t
529	njs_query_string_encode(njs_chb_t *chain, njs_str_t *str)
530	{
531	    size_t  size;
532	    u_char  *p, *start, *end;
533	
534	    static const uint32_t  escape[] = {
535	        0xffffffff,  /* 1111 1111 1111 1111  1111 1111 1111 1111 */
536	
537	                     /* ?>=< ;:98 7654 3210  /.-, +*)( '&%$ #"!  */
538	        0xfc00987d,  /* 1111 1100 0000 0000  1001 1000 0111 1101 */
539	
540	                     /* _^]\ [ZYX WVUT SRQP  ONML KJIH GFED CBA@ */
541	        0x78000001,  /* 0111 1000 0000 0000  0000 0000 0000 0001 */
542	
543	                     /*  ~}| {zyx wvut srqp  onml kjih gfed cba` */
544	        0xb8000001,  /* 1011 1000 0000 0000  0000 0000 0000 0001 */
545	
546	        0xffffffff,  /* 1111 1111 1111 1111  1111 1111 1111 1111 */
547	        0xffffffff,  /* 1111 1111 1111 1111  1111 1111 1111 1111 */
548	        0xffffffff,  /* 1111 1111 1111 1111  1111 1111 1111 1111 */
549	        0xffffffff,  /* 1111 1111 1111 1111  1111 1111 1111 1111 */
550	    };
551	
552	    if (chain->error) {
553	        return NJS_ERROR;
554	    }
555	
556	    if (str->length == 0) {
557	        return NJS_OK;
558	    }
559	
560	    p = str->start;
561	    end = p + str->length;
562	    size = str->length;
563	
564	    while (p < end) {
565	        if (njs_need_escape(escape, *p++)) {
566	            size += 2;
567	        }
568	    }
569	
570	    start = njs_chb_reserve(chain, size);
571	    if (njs_slow_path(start == NULL)) {
572	        return NJS_ERROR;
573	    }
574	
575	    if (size == str->length) {
576	        memcpy(start, str->start, str->length);
577	        njs_chb_written(chain, str->length);
578	        return NJS_OK;
579	    }
580	
581	    (void) njs_string_encode(escape, str->length, str->start, start);
582	
583	    njs_chb_written(chain, size);
584	
585	    return NJS_OK;
586	}
