617	        njs_value_string_get(vm, string, &str);
618	        return njs_query_string_encode(chain, &str);
619	    }
620	
621	    ret = njs_vm_invoke(vm, encoder, string, 1, njs_value_arg(&retval));
622	    if (njs_slow_path(ret != NJS_OK)) {
623	        return ret;
624	    }
625	
626	    if (njs_slow_path(!njs_value_is_string(njs_value_arg(&retval)))) {
627	        ret = njs_value_to_string(vm, njs_value_arg(&retval),
628	                                  njs_value_arg(&retval));
629	        if (njs_slow_path(ret != NJS_OK)) {
630	            return NJS_ERROR;
631	        }
632	    }
633	
634	    njs_value_string_get(vm, njs_value_arg(&retval), &str);
