676	static njs_int_t
677	njs_query_string_stringify(njs_vm_t *vm, njs_value_t *args, njs_uint_t nargs,
678	    njs_index_t unused, njs_value_t *retval)
679	{
680	    int64_t             len, keys_length;
681	    uint32_t            n, i;
682	    njs_int_t           ret;
683	    njs_str_t           sep, eq;
684	    njs_chb_t           chain;
685	    njs_value_t         *this, *object, *arg, *options, *val, *keys;
686	    njs_function_t      *encode;
687	    njs_opaque_value_t  value, result, key, *string;
688	
689	    encode = NULL;
690	    sep = njs_sep_default;
691	    eq = njs_eq_default;
692	
693	    this = njs_argument(args, 0);
694	    object = njs_arg(args, nargs, 1);
695	
696	    if (njs_slow_path(!njs_value_is_object(object))) {
697	        njs_vm_value_string_create(vm, retval, (u_char *) "", 0);
698	        return NJS_OK;
699	    }
700	
701	    arg = njs_arg(args, nargs, 2);
702	    if (!njs_value_is_null_or_undefined(arg)) {
703	        ret = njs_value_to_string(vm, arg, arg);
704	        if (njs_slow_path(ret != NJS_OK)) {
705	            return ret;
706	        }
707	
708	        if (njs_value_string_length(vm, arg) > 0) {
709	            njs_value_string_get(vm, arg, &sep);
710	        }
711	    }
712	
713	    arg = njs_arg(args, nargs, 3);
714	    if (!njs_value_is_null_or_undefined(arg)) {
715	        ret = njs_value_to_string(vm, arg, arg);
716	        if (njs_slow_path(ret != NJS_OK)) {
717	            return ret;
718	        }
719	
720	        if (njs_value_string_length(vm, arg) > 0) {
721	            njs_value_string_get(vm, arg, &eq);
722	        }
723	    }
724	
725	    options = njs_arg(args, nargs, 4);
726	
727	    if (njs_value_is_object(options)) {
728	        val = njs_vm_object_prop(vm, options, &njs_encode_uri_str, &value);
729	
730	        if (val != NULL) {
731	            if (njs_slow_path(!njs_value_is_function(val))) {
732	                njs_vm_type_error(vm, "option encodeURIComponent is not "
733	                                  "a function");
734	                return NJS_ERROR;
735	            }
736	
737	            encode = njs_value_function(val);
738	        }
739	    }
740	
741	    if (encode == NULL) {
742	        val = njs_vm_object_prop(vm, this, &njs_escape_str, &value);
743	
744	        if (val == NULL || !njs_value_is_function(val)) {
