759	    (void) njs_vm_array_length(vm, keys, &keys_length);
760	
761	    string = (njs_opaque_value_t *) njs_vm_array_start(vm, keys);
762	    if (njs_slow_path(string == NULL)) {
763	        return NJS_ERROR;
764	    }
765	
766	    for (n = 0; n < keys_length; n++, string++) {
767	        ret = njs_value_property_val(vm, object, njs_value_arg(string),
768	                                     njs_value_arg(&value));
769	        if (njs_slow_path(ret == NJS_ERROR)) {
770	            goto failed;
771	        }
772	
773	        if (njs_value_is_array(njs_value_arg(&value))) {
774	            (void) njs_vm_array_length(vm, njs_value_arg(&value), &len);
775	
776	            for (i = 0; i < len; i++) {
777	                njs_value_number_set(njs_value_arg(&key), i);
778	                ret = njs_value_property_val(vm, njs_value_arg(&value),
779	                                             njs_value_arg(&key),
780	                                             njs_value_arg(&result));
781	                if (njs_slow_path(ret == NJS_ERROR)) {
782	                    goto failed;
783	                }
784	
785	                if (chain.last != NULL) {
786	                    njs_chb_append(&chain, sep.start, sep.length);
787	                }
788	
789	                ret = njs_query_string_push(vm, &chain, njs_value_arg(string),
790	                                            njs_value_arg(&result), &eq,
791	                                            encode);
792	                if (njs_slow_path(ret != NJS_OK)) {
793	                    goto failed;
794	                }
795	            }
796	
797	            continue;
798	        }
799	
800	        if (n != 0) {
801	            njs_chb_append(&chain, sep.start, sep.length);
802	        }
803	
804	        ret = njs_query_string_push(vm, &chain, njs_value_arg(string),
805	                                    njs_value_arg(&value), &eq, encode);
806	        if (njs_slow_path(ret != NJS_OK)) {
807	            goto failed;
808	        }
809	    }
810	
811	    ret = njs_vm_value_string_create_chb(vm, retval, &chain);
812	
813	failed:
814	
815	    njs_chb_destroy(&chain);
816	
817	    return ret;
818	}
