130	    }
131	
132	    ret = qjs_query_string_parser(cx, str.start, str.start + str.length,
133	                                  sep.start ? &sep : NULL,
134	                                  eq.start ? &eq : NULL, decode, max_keys);
135	
136	    JS_FreeValue(cx, decode);
137	
138	    if (sep.start != NULL) {
139	        JS_FreeCString(cx, (char *) sep.start);
140	    }
141	
142	    if (eq.start != NULL) {
143	        JS_FreeCString(cx, (char *) eq.start);
144	    }
145	
146	    JS_FreeCString(cx, (char *) str.start);
147	
148	    return ret;
149	
150	fail:
151	
152	    JS_FreeValue(cx, decode);
153	
154	    if (sep.start != NULL) {
155	        JS_FreeCString(cx, (char *) sep.start);
156	    }
157	
158	    if (eq.start != NULL) {
159	        JS_FreeCString(cx, (char *) eq.start);
160	    }
161	
162	    if (str.start != NULL) {
163	        JS_FreeCString(cx, (char *) str.start);
164	    }
165	
166	    return JS_EXCEPTION;
167	}
