256	static JSValue
257	qjs_query_string_escape(JSContext *cx, JSValueConst this_val, int argc,
258	    JSValueConst *argv)
259	{
260	    JSValue    ret;
261	    njs_str_t  str;
262	    njs_chb_t  chain;
263	
264	    str.start = (u_char *) JS_ToCStringLen(cx, &str.length, argv[0]);
265	    if (str.start == NULL) {
266	        return JS_EXCEPTION;
267	    }
