272	        JS_FreeCString(cx, (char *) str.start);
273	        njs_chb_destroy(&chain);
274	        return JS_EXCEPTION;
275	    }
276	
277	    ret = qjs_string_create_chb(cx, &chain);
278	
279	    JS_FreeCString(cx, (char *) str.start);
280	
281	    return ret;
282	}
