309	static u_char *
310	qjs_query_string_match(u_char *p, u_char *end, const njs_str_t *v)
311	{
312	    size_t  length;
313	
314	    length = v->length;
315	
316	    if (length == 1) {
317	        p = njs_strlchr(p, end, v->start[0]);
318	
319	        if (p == NULL) {
320	            p = end;
321	        }
322	
323	        return p;
324	    }
325	
326	    while (p <= (end - length)) {
327	        if (memcmp(p, v->start, length) == 0) {
328	            return p;
329	        }
330	
331	        p++;
332	    }
333	
334	    return end;
335	}
