338	static int
339	qjs_query_string_append(JSContext *cx, JSValue object, const u_char *key,
340	    size_t key_size, const u_char *val, size_t val_size, JSValue decoder)
341	{
342	    JSAtom    prop;
343	    JSValue   name, value, prev, length, ret;
344	    uint32_t  len;
345	
346	    if (JS_IsNullOrUndefined(decoder)) {
347	        name = qjs_query_string_decode(cx, key, key_size);
348	        if (JS_IsException(name)) {
349	            return -1;
350	        }
351	
352	        value = qjs_query_string_decode(cx, val, val_size);
353	        if (JS_IsException(value)) {
354	            JS_FreeValue(cx, name);
355	            return -1;
356	        }
357	
358	    } else {
359	        name = JS_NewStringLen(cx, (const char *) key, key_size);
360	        if (JS_IsException(name)) {
361	            return -1;
362	        }
363	
364	        ret = JS_Call(cx, decoder, JS_UNDEFINED, 1, &name);
365	        JS_FreeValue(cx, name);
366	        if (JS_IsException(ret)) {
367	            return -1;
368	        }
369	
370	        name = ret;
371	
372	        value = JS_NewStringLen(cx, (const char *) val, val_size);
373	        if (JS_IsException(value)) {
374	            return -1;
375	        }
376	
377	        ret = JS_Call(cx, decoder, JS_UNDEFINED, 1, &value);
378	        JS_FreeValue(cx, value);
379	        if (JS_IsException(ret)) {
380	            JS_FreeValue(cx, name);
381	            return -1;
382	        }
383	
384	        value = ret;
385	    }
386	
387	    prop = JS_ValueToAtom(cx, name);
388	    JS_FreeValue(cx, name);
389	    if (prop == JS_ATOM_NULL) {
390	        JS_FreeValue(cx, value);
391	        return -1;
392	    }
393	
394	    prev = JS_GetProperty(cx, object, prop);
395	    if (JS_IsException(prev)) {
396	        JS_FreeAtom(cx, prop);
397	        JS_FreeValue(cx, value);
398	        return -1;
399	    }
400	
401	    if (JS_IsUndefined(prev)) {
402	        if (JS_SetProperty(cx, object, prop, value) < 0) {
403	            value = JS_UNDEFINED;
404	            goto exception;
405	        }
406	
407	    } else if (qjs_is_array(cx, prev)) {
408	        length = JS_GetPropertyStr(cx, prev, "length");
409	
410	        if (JS_ToUint32(cx, &len, length) < 0) {
411	            JS_FreeValue(cx, length);
412	            goto exception;
413	        }
414	
415	        JS_FreeValue(cx, length);
416	
417	        if (JS_SetPropertyUint32(cx, prev, len, value) < 0) {
418	            value = JS_UNDEFINED;
419	            goto exception;
420	        }
421	
422	        JS_FreeValue(cx, prev);
423	        prev = JS_UNDEFINED;
424	
425	    } else {
426	        ret = JS_NewArray(cx);
427	        if (JS_IsException(ret)) {
428	            goto exception;
429	        }
430	
431	        if (JS_SetPropertyUint32(cx, ret, 0, prev) < 0) {
432	            prev = JS_UNDEFINED;
433	            JS_FreeValue(cx, ret);
434	            goto exception;
435	        }
436	
437	        prev = JS_UNDEFINED;
438	
439	        if (JS_SetPropertyUint32(cx, ret, 1, value) < 0) {
440	            value = JS_UNDEFINED;
441	            JS_FreeValue(cx, ret);
442	            goto exception;
443	        }
444	
445	        value = JS_UNDEFINED;
446	
447	        if (JS_SetProperty(cx, object, prop, ret) < 0) {
448	            goto exception;
449	        }
450	    }
451	
452	    JS_FreeAtom(cx, prop);
453	
454	    return 0;
455	
456	exception:
457	
458	    JS_FreeAtom(cx, prop);
459	    JS_FreeValue(cx, prev);
460	    JS_FreeValue(cx, value);
461	
462	    return -1;
463	}
