465	
466	static JSValue
467	qjs_query_string_parser(JSContext *cx, u_char *query, u_char *end,
468	    njs_str_t *sep, njs_str_t *eq, JSValue decode, unsigned max_keys)
469	{
470	    size_t     size;
471	    u_char     *part, *key, *val;
472	    JSValue    obj;
473	    unsigned   count;
474	    njs_str_t  sep_val, eq_val;
475	
476	    if (sep == NULL || sep->length == 0) {
477	        sep = &sep_val;
478	        sep->start = (u_char *) "&";
479	        sep->length = 1;
480	    }
481	
482	    if (eq == NULL || eq->length == 0) {
483	        eq = &eq_val;
484	        eq->start = (u_char *) "=";
485	        eq->length = 1;
486	    }
487	
488	    obj = JS_NewObject(cx);
489	    if (JS_IsException(obj)) {
490	        return JS_EXCEPTION;
491	    }
492	
493	    count = 0;
494	
495	    key = query;
496	
497	    while (key < end) {
498	        if (count++ == max_keys) {
499	            break;
500	        }
501	
502	        part = qjs_query_string_match(key, end, sep);
503	
504	        if (part == key) {
505	            goto next;
506	        }
507	
508	        val = qjs_query_string_match(key, part, eq);
509	
510	        size = val - key;
511	
512	        if (val != part) {
513	            val += eq->length;
514	        }
515	
516	        if (qjs_query_string_append(cx, obj, key, size, val, part - val,
517	                                     decode) < 0)
518	        {
519	            JS_FreeValue(cx, obj);
520	            return JS_EXCEPTION;
521	        }
522	
523	next:
524	
525	        key = part + sep->length;
526	    }
527	
528	    return obj;
529	}
