538	
539	static inline u_char *
540	qjs_string_encode(const uint32_t *escape, size_t size, const u_char *src,
541	    u_char *dst)
542	{
543	    uint8_t              byte;
544	    static const u_char  hex[] = "0123456789ABCDEF";
545	
546	    do {
547	        byte = *src++;
548	
549	        if (qjs_need_escape(escape, byte)) {
550	            *dst++ = '%';
551	            *dst++ = hex[byte >> 4];
552	            *dst++ = hex[byte & 0xf];
553	
554	        } else {
555	            *dst++ = byte;
556	        }
557	
558	        size--;
559	
560	    } while (size != 0);
561	
562	    return dst;
563	}
