565	
566	static int
567	qjs_query_string_encode(njs_chb_t *chain, njs_str_t *str)
568	{
569	    size_t  size;
570	    u_char  *p, *start, *end;
571	
572	    static const uint32_t  escape[] = {
573	        0xffffffff,  /* 1111 1111 1111 1111  1111 1111 1111 1111 */
574	
575	                     /* ?>=< ;:98 7654 3210  /.-, +*)( '&%$ #"!  */
576	        0xfc00987d,  /* 1111 1100 0000 0000  1001 1000 0111 1101 */
577	
578	                     /* _^]\ [ZYX WVUT SRQP  ONML KJIH GFED CBA@ */
579	        0x78000001,  /* 0111 1000 0000 0000  0000 0000 0000 0001 */
580	
581	                     /*  ~}| {zyx wvut srqp  onml kjih gfed cba` */
582	        0xb8000001,  /* 1011 1000 0000 0000  0000 0000 0000 0001 */
583	
584	        0xffffffff,  /* 1111 1111 1111 1111  1111 1111 1111 1111 */
585	        0xffffffff,  /* 1111 1111 1111 1111  1111 1111 1111 1111 */
586	        0xffffffff,  /* 1111 1111 1111 1111  1111 1111 1111 1111 */
587	        0xffffffff,  /* 1111 1111 1111 1111  1111 1111 1111 1111 */
588	    };
589	
590	    if (chain->error) {
591	        return -1;
592	    }
593	
594	    if (str->length == 0) {
595	        return 0;
596	    }
597	
598	    p = str->start;
599	    end = p + str->length;
600	
601	    size = str->length;
602	    while (p < end) {
603	        if (qjs_need_escape(escape, *p++)) {
604	            size += 2;
605	        }
606	    }
607	
608	    start = njs_chb_reserve(chain, size);
609	    if (start == NULL) {
610	        return -1;
611	    }
612	
613	    if (size == str->length) {
614	        memcpy(start, str->start, str->length);
615	        njs_chb_written(chain, str->length);
616	        return 0;
617	    }
618	
619	    qjs_string_encode(escape, str->length, str->start, start);
620	
621	    njs_chb_written(chain, size);
622	
623	    return 0;
624	}
