627	static inline int
628	qjs_query_string_encoder_call(JSContext *cx, njs_chb_t *chain,
629	    JSValue encoder, JSValue value)
630	{
631	    int        rc;
632	    JSValue    ret;
633	    njs_str_t  str;
634	
635	    if (JS_IsNullOrUndefined(encoder)) {
636	        str.start = (u_char *) JS_ToCStringLen(cx, &str.length, value);
637	        if (str.start == NULL) {
638	            return -1;
639	        }
640	
641	        rc = qjs_query_string_encode(chain, &str);
642	        JS_FreeCString(cx, (char *) str.start);
643	        return rc;
644	    }
645	
646	    ret = JS_Call(cx, encoder, JS_UNDEFINED, 1, &value);
647	    if (JS_IsException(ret)) {
648	        return -1;
649	    }
650	
651	    str.start = (u_char *) JS_ToCStringLen(cx, &str.length, ret);
652	    JS_FreeValue(cx, ret);
653	    if (str.start == NULL) {
654	        return -1;
655	    }
656	
657	    njs_chb_append_str(chain, &str);
658	
659	    JS_FreeCString(cx, (char *) str.start);
660	
661	    return 0;
662	}
