665	static inline int
666	qjs_query_string_push(JSContext *cx, njs_chb_t *chain, JSValue key,
667	    JSValue value, njs_str_t *eq, JSValue encoder)
668	{
669	    if (qjs_query_string_encoder_call(cx, chain, encoder, key) < 0) {
670	        return -1;
671	    }
672	
673	    njs_chb_append(chain, eq->start, eq->length);
674	
675	    if (JS_IsNumber(value)
676	        || JS_IsBool(value)
677	        || JS_IsString(value))
678	    {
679	        return qjs_query_string_encoder_call(cx, chain, encoder, value);
680	    }
681	
682	    return 0;
683	}
