686	static inline int
687	qjs_query_string_push_array(JSContext *cx, njs_chb_t *chain, JSValue key,
688	    JSValue array, njs_str_t *eq, njs_str_t *sep, JSValue encoder)
689	{
690	    int       rc;
691	    JSValue   val, len;
692	    uint32_t  i, length;
693	
694	    len = JS_GetPropertyStr(cx, array, "length");
695	    if (JS_IsException(len)) {
696	        return -1;
697	    }
698	
699	    if (JS_ToUint32(cx, &length, len) < 0) {
700	        JS_FreeValue(cx, len);
701	        return -1;
702	    }
703	
704	    JS_FreeValue(cx, len);
705	
706	    for (i = 0; i < length; i++) {
