708	            njs_chb_append(chain, sep->start, sep->length);
709	        }
710	
711	        val = JS_GetPropertyUint32(cx, array, i);
712	        if (JS_IsException(val)) {
713	            return -1;
714	        }
715	
716	        rc = qjs_query_string_push(cx, chain, key, val, eq, encoder);
717	        JS_FreeValue(cx, val);
718	        if (rc != 0) {
719	            return -1;
720	        }
721	    }
722	
723	    return 0;
724	}
