726	
727	static JSValue
728	qjs_query_string_stringify_internal(JSContext *cx, JSValue obj, njs_str_t *sep,
729	    njs_str_t *eq, JSValue encoder)
730	{
731	    int             rc;
732	    uint32_t        n, length;
733	    JSValue         key, val;
734	    njs_str_t       sep_val, eq_val;
735	    njs_chb_t       chain;
736	    JSPropertyEnum  *ptab;
737	
738	    if (!JS_IsObject(obj)) {
739	        return JS_NewString(cx, "");
740	    }
741	
742	    if (JS_GetOwnPropertyNames(cx, &ptab, &length, obj,
743	                               JS_GPN_STRING_MASK | JS_GPN_ENUM_ONLY)
744	        < 0)
745	    {
746	        return JS_EXCEPTION;
747	    }
748	
749	    if (sep == NULL || sep->length == 0) {
750	        sep = &sep_val;
751	        sep->start = (u_char *) "&";
752	        sep->length = 1;
753	    }
754	
755	    if (eq == NULL || eq->length == 0) {
756	        eq = &eq_val;
757	        eq->start = (u_char *) "=";
758	        eq->length = 1;
759	    }
760	
761	    NJS_CHB_CTX_INIT(&chain, cx);
762	
763	    for (n = 0; n < length; n++) {
764	        val = JS_GetProperty(cx, obj, ptab[n].atom);
765	        if (JS_IsException(val)) {
766	            goto fail;
767	        }
768	
769	        if (qjs_is_array(cx, val)) {
770	            key = JS_AtomToString(cx, ptab[n].atom);
771	            if (JS_IsException(key)) {
772	                JS_FreeValue(cx, val);
773	                goto fail;
774	            }
775	
776	            rc = qjs_query_string_push_array(cx, &chain, key, val, eq, sep,
777	                                             encoder);
778	            JS_FreeValue(cx, key);
779	            JS_FreeValue(cx, val);
780	            if (rc != 0) {
781	                goto fail;
782	            }
783	
784	            continue;
785	        }
786	
787	        if (n != 0) {
788	            njs_chb_append(&chain, sep->start, sep->length);
789	        }
790	
791	        key = JS_AtomToString(cx, ptab[n].atom);
792	        if (JS_IsException(key)) {
793	            JS_FreeValue(cx, val);
794	            goto fail;
795	        }
796	
797	        rc = qjs_query_string_push(cx, &chain, key, val, eq, encoder);
798	        JS_FreeValue(cx, key);
799	        JS_FreeValue(cx, val);
